class SecureEncryptionManager(private val context: Context) {

    companion object {
        private const val KEYSTORE_PROVIDER = "AndroidKeyStore"
        private const val KEY_ALIAS_PAYMENT = "payment_encryption_key"
        private const val KEY_ALIAS_WALLET = "wallet_encryption_key"
        private const val GCM_TAG_LENGTH = 128
        private const val ENCRYPTED_PREFS_FILE = "secure_payment_prefs"
    }

    private val keyStore: KeyStore = KeyStore.getInstance(KEYSTORE_PROVIDER).apply { load(null) }

    private val masterKey: MasterKey by lazy {
        MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .setRequestStrongBoxBacked(true)
            .build()
    }

    val encryptedPreferences by lazy {
        EncryptedSharedPreferences.create(
            context,
            ENCRYPTED_PREFS_FILE,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    init {
        ensureKeysExist()
    }

    private fun ensureKeysExist() {
        if (!keyStore.containsAlias(KEY_ALIAS_PAYMENT)) {
            generateKey(KEY_ALIAS_PAYMENT)
        }
        if (!keyStore.containsAlias(KEY_ALIAS_WALLET)) {
            generateKey(KEY_ALIAS_WALLET)
        }
    }

    private fun generateKey(alias: String) {
        val keyGenerator = KeyGenerator.getInstance(
            KeyProperties.KEY_ALGORITHM_AES,
            KEYSTORE_PROVIDER
        )

        val builder = KeyGenParameterSpec.Builder(
            alias,
            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
            .setKeySize(256)
            .setUserAuthenticationRequired(false)

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            builder.setIsStrongBoxBacked(isStrongBoxAvailable())
        }

        keyGenerator.init(builder.build())
        keyGenerator.generateKey()
    }

    private fun isStrongBoxAvailable(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            context.packageManager.hasSystemFeature("android.hardware.strongbox_keystore")
        } else false
    }

    fun encrypt(data: String, keyAlias: String = KEY_ALIAS_PAYMENT): String {
        try {
            val key = keyStore.getKey(keyAlias, null) as SecretKey
            val cipher = Cipher.getInstance("AES/GCM/NoPadding")
            cipher.init(Cipher.ENCRYPT_MODE, key)

            val iv = cipher.iv
            val encryptedBytes = cipher.doFinal(data.toByteArray(Charsets.UTF_8))

            val combined = ByteArray(iv.size + encryptedBytes.size)
            System.arraycopy(iv, 0, combined, 0, iv.size)
            System.arraycopy(encryptedBytes, 0, combined, iv.size, encryptedBytes.size)

            return Base64.encodeToString(combined, Base64.NO_WRAP)
        } catch (e: Exception) {
            throw PaymentError.EncryptionError("Encryption failed", e)
        }
    }

    fun decrypt(encryptedData: String, keyAlias: String = KEY_ALIAS_PAYMENT): String {
        try {
            val combined = Base64.decode(encryptedData, Base64.NO_WRAP)
            val iv = combined.copyOfRange(0, 12)
            val encrypted = combined.copyOfRange(12, combined.size)

            val key = keyStore.getKey(keyAlias, null) as SecretKey
            val cipher = Cipher.getInstance("AES/GCM/NoPadding")
            val spec = GCMParameterSpec(GCM_TAG_LENGTH, iv)
            cipher.init(Cipher.DECRYPT_MODE, key, spec)

            val decryptedBytes = cipher.doFinal(encrypted)
            return String(decryptedBytes, Charsets.UTF_8)
        } catch (e: Exception) {
            throw PaymentError.EncryptionError("Decryption failed", e)
        }
    }

    fun secureStore(key: String, value: String) {
        encryptedPreferences.edit().putString(key, value).apply()
    }

    fun secureRetrieve(key: String): String? {
        return encryptedPreferences.getString(key, null)
    }

    fun secureRemove(key: String) {
        encryptedPreferences.edit().remove(key).apply()
    }

    fun clearAllSecureData() {
        encryptedPreferences.edit().clear().apply()
    }
}

