class DeviceIntegrityChecker(private val context: Context) {

    companion object {
        private const val TAG = "DeviceIntegrity"
        private const val RISK_THRESHOLD_BLOCK = 70
        private const val RISK_THRESHOLD_WARN = 40
    }

    suspend fun performFullIntegrityCheck(): DeviceIntegrityResult {
        val checks = mutableMapOf<String, Boolean>()

        val isEmulator = detectEmulator()
        checks["emulator_check"] = !isEmulator

        val isRooted = detectRoot()
        checks["root_check"] = !isRooted

        val isDebuggerAttached = detectDebugger()
        checks["debugger_check"] = !isDebuggerAttached

        val isHookingDetected = detectHookingFrameworks()
        checks["hooking_check"] = !isHookingDetected

        val isAppTampered = detectAppTampering()
        checks["tampering_check"] = !isAppTampered

        val isInstallerValid = verifyInstaller()
        checks["installer_check"] = isInstallerValid

        val isSecureEnvironment = checkSecureEnvironment()
        checks["secure_env_check"] = isSecureEnvironment

        val playIntegrityToken = try {
            getPlayIntegrityToken()
        } catch (e: Exception) {
            Log.w(TAG, "Play Integrity check failed: ${e.message}")
            null
        }
        checks["play_integrity"] = playIntegrityToken != null

        val riskScore = calculateRiskScore(checks, isEmulator, isRooted, isDebuggerAttached)

        val isValid = riskScore < RISK_THRESHOLD_BLOCK

        return DeviceIntegrityResult(
            isIntegrityValid = isValid,
            isEmulator = isEmulator,
            isRooted = isRooted,
            isDebuggerAttached = isDebuggerAttached,
            integrityToken = playIntegrityToken,
            riskScore = riskScore,
            checks = checks
        )
    }

    private fun detectEmulator(): Boolean {
        val indicators = listOf(
            Build.FINGERPRINT.startsWith("generic"),
            Build.FINGERPRINT.startsWith("unknown"),
            Build.MODEL.contains("google_sdk"),
            Build.MODEL.contains("Emulator"),
            Build.MODEL.contains("Android SDK built for x86"),
            Build.MANUFACTURER.contains("Genymotion"),
            Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic"),
            "google_sdk" == Build.PRODUCT,
            Build.HARDWARE.contains("goldfish"),
            Build.HARDWARE.contains("ranchu"),
            Build.BOARD.contains("unknown"),
            Build.PRODUCT.contains("sdk"),
            Build.PRODUCT.contains("emulator")
        )

        val emulatorFileIndicators = listOf(
            "/dev/socket/qemud",
            "/dev/qemu_pipe",
            "/system/lib/libc_malloc_debug_qemu.so",
            "/sys/qemu_trace",
            "/system/bin/qemu-props"
        )

        val fileIndicatorFound = emulatorFileIndicators.any { path ->
            try {
                java.io.File(path).exists()
            } catch (e: Exception) {
                false
            }
        }

        return indicators.count { it } >= 2 || fileIndicatorFound
    }

    private fun detectRoot(): Boolean {
        val rootIndicators = listOf(
            "/system/app/Superuser.apk",
            "/sbin/su",
            "/system/bin/su",
            "/system/xbin/su",
            "/data/local/xbin/su",
            "/data/local/bin/su",
            "/system/sd/xbin/su",
            "/system/bin/failsafe/su",
            "/data/local/su",
            "/su/bin/su",
            "/system/xbin/daemonsu",
            "/system/etc/init.d/99telecominfra"
        )

        val rootFileFound = rootIndicators.any { path ->
            try {
                java.io.File(path).exists()
            } catch (e: Exception) {
                false
            }
        }

        val suCommandAvailable = try {
            val process = Runtime.getRuntime().exec(arrayOf("/system/xbin/which", "su"))
            process.inputStream.bufferedReader().readLine() != null
        } catch (e: Exception) {
            false
        }

        val buildTagsRooted = Build.TAGS?.contains("test-keys") == true

        return rootFileFound || suCommandAvailable || buildTagsRooted
    }

    private fun detectDebugger(): Boolean {
        return android.os.Debug.isDebuggerConnected() ||
                android.os.Debug.waitingForDebugger()
    }

    private fun detectHookingFrameworks(): Boolean {
        val hookingIndicators = listOf(
            "de.robv.android.xposed",
            "de.robv.android.xposed.installer",
            "com.saurik.substrate",
            "io.va.exposed",
            "com.topjohnwu.magisk",
            "org.meowcat.edxposed.manager",
            "org.lsposed.manager"
        )

        return hookingIndicators.any { packageName ->
            try {
                context.packageManager.getPackageInfo(packageName, 0)
                true
            } catch (e: Exception) {
                false
            }
        }
    }

    private fun detectAppTampering(): Boolean {
        return try {
            val packageInfo = context.packageManager.getPackageInfo(
                context.packageName,
                android.content.pm.PackageManager.GET_SIGNATURES
            )
            // In production, compare against known signing certificate hash
            val signatures = packageInfo.signatures
            if (signatures.isNullOrEmpty()) {
                true // No signatures = tampered
            } else {
                val sig = signatures[0]
                val md = MessageDigest.getInstance("SHA-256")
                val digest = md.digest(sig.toByteArray())
                val hash = Base64.encodeToString(digest, Base64.NO_WRAP)
                // TODO: Compare hash against expected value from secure config
                Log.d(TAG, "App signature hash: $hash")
                false
            }
        } catch (e: Exception) {
            Log.e(TAG, "Tampering detection failed", e)
            true
        }
    }

    private fun verifyInstaller(): Boolean {
        val validInstallers = listOf(
            "com.android.vending",      // Google Play Store
            "com.google.android.feedback" // Google Play Store (older)
        )

        val installer = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            context.packageManager.getInstallSourceInfo(context.packageName).installingPackageName
        } else {
            @Suppress("DEPRECATION")
            context.packageManager.getInstallerPackageName(context.packageName)
        }

        // Allow null installer during development
        return installer == null || validInstallers.contains(installer)
    }

    private fun checkSecureEnvironment(): Boolean {
        val isScreenLockEnabled = try {
            val keyguardManager = context.getSystemService(Context.KEYGUARD_SERVICE) as android.app.KeyguardManager
            keyguardManager.isDeviceSecure
        } catch (e: Exception) {
            false
        }

        val isDeveloperOptionsEnabled = try {
            Settings.Secure.getInt(
                context.contentResolver,
                Settings.Global.DEVELOPMENT_SETTINGS_ENABLED, 0
            ) != 0
        } catch (e: Exception) {
            false
        }

        val isAdbEnabled = try {
            Settings.Global.getInt(
                context.contentResolver,
                Settings.Global.ADB_ENABLED, 0
            ) != 0
        } catch (e: Exception) {
            false
        }

        return isScreenLockEnabled && !isDeveloperOptionsEnabled && !isAdbEnabled
    }

    private suspend fun getPlayIntegrityToken(): String? {
        return suspendCancellableCoroutine { continuation ->
            val integrityManager = IntegrityManagerFactory.create(context)
            val nonce = generateNonce()

            integrityManager.requestIntegrityToken(
                IntegrityTokenRequest.builder()
                    .setNonce(nonce)
                    .build()
            ).addOnSuccessListener { response ->
                continuation.resume(response.token())
            }.addOnFailureListener { exception ->
                Log.e(TAG, "Play Integrity request failed", exception)
                continuation.resume(null)
            }
        }
    }

    private fun generateNonce(): String {
        val bytes = ByteArray(32)
        SecureRandom().nextBytes(bytes)
        return Base64.encodeToString(bytes, Base64.URL_SAFE or Base64.NO_WRAP)
    }

    private fun calculateRiskScore(
        checks: Map<String, Boolean>,
        isEmulator: Boolean,
        isRooted: Boolean,
        isDebuggerAttached: Boolean
    ): Int {
        var score = 0

        if (isEmulator) score += 30
        if (isRooted) score += 35
        if (isDebuggerAttached) score += 25

        if (checks["hooking_check"] == false) score += 40
        if (checks["tampering_check"] == false) score += 50
        if (checks["installer_check"] == false) score += 15
        if (checks["secure_env_check"] == false) score += 10
        if (checks["play_integrity"] == false) score += 20

        return score.coerceAtMost(100)
    }
}

