// Security: Rate Limiter
// ============================================================

class TransactionRateLimiter {
    companion object {
        private const val MAX_TRANSACTIONS_PER_MINUTE = 5
        private const val MAX_TRANSACTIONS_PER_HOUR = 20
        private const val MAX_FAILED_ATTEMPTS = 3
        private const val LOCKOUT_DURATION_MS = 15 * 60 * 1000L // 15 minutes
    }

    private val transactionTimestamps = Collections.synchronizedList(mutableListOf<Long>())
    private val failedAttempts = AtomicInteger(0)
    private var lockoutUntil: Long = 0

    fun checkRateLimit(): Boolean {
        val now = System.currentTimeMillis()

        if (now < lockoutUntil) {
            throw PaymentError.RateLimitExceeded(
                "Account temporarily locked. Try again after ${(lockoutUntil - now) / 1000} seconds."
            )
        }

        synchronized(transactionTimestamps) {
            transactionTimestamps.removeAll { now - it > 3600000 }

            val lastMinuteCount = transactionTimestamps.count { now - it < 60000 }
            if (lastMinuteCount >= MAX_TRANSACTIONS_PER_MINUTE) {
                throw PaymentError.RateLimitExceeded("Too many transactions per minute. Please wait.")
            }

            if (transactionTimestamps.size >= MAX_TRANSACTIONS_PER_HOUR) {
                throw PaymentError.RateLimitExceeded("Hourly transaction limit reached.")
            }
        }

        return true
    }

    fun recordTransaction() {
        transactionTimestamps.add(System.currentTimeMillis())
        failedAttempts.set(0)
    }

    fun recordFailure() {
        val attempts = failedAttempts.incrementAndGet()
        if (attempts >= MAX_FAILED_ATTEMPTS) {
            lockoutUntil = System.currentTimeMillis() + LOCKOUT_DURATION_MS
            failedAttempts.set(0)
        }
    }

    fun reset() {
        transactionTimestamps.clear()
        failedAttempts.set(0)
        lockoutUntil = 0
    }
}

