class WalletManager(
    private val context: Context,
    private val encryptionManager: SecureEncryptionManager,
    private val httpClient: OkHttpClient
) {
    companion object {
        private const val TAG = "WalletManager"
        private const val KEY_WALLET_BALANCE = "wallet_balance"
        private const val KEY_WALLET_CURRENCY = "wallet_currency"
        private const val KEY_WALLET_LAST_SYNC = "wallet_last_sync"
        private const val BASE_URL = "https://api.yourpaymentserver.com/v1"
    }

    private val _walletBalance = MutableStateFlow<WalletBalance?>(null)
    val walletBalance: StateFlow<WalletBalance?> = _walletBalance.asStateFlow()

    private val _transactions = MutableStateFlow<List<TransactionRecord>>(emptyList())
    val transactions: StateFlow<List<TransactionRecord>> = _transactions.asStateFlow()

    suspend fun refreshBalance(authToken: String): WalletBalance {
        return withContext(Dispatchers.IO) {
            try {
                val request = Request.Builder()
                    .url("$BASE_URL/wallet/balance")
                    .addHeader("Authorization", "Bearer $authToken")
                    .addHeader("X-Request-Id", UUID.randomUUID().toString())
                    .get()
                    .build()

                val response = httpClient.newCall(request).execute()

                if (!response.isSuccessful) {
                    throw PaymentError.NetworkError("Failed to fetch balance: ${response.code}")
                }

                val body = response.body?.string()
                    ?: throw PaymentError.NetworkError("Empty response body")

                val json = JSONObject(body)
                val balance = WalletBalance(
                    available = BigDecimal(json.getString("available")),
                    pending = BigDecimal(json.getString("pending")),
                    currency = json.getString("currency")
                )

                // Cache encrypted balance locally
                cacheBalance(balance)
                _walletBalance.value = balance
                balance
            } catch (e: PaymentError) {
                throw e
            } catch (e: Exception) {
                // Fall back to cached balance
                val cached = getCachedBalance()
                if (cached != null) {
                    _walletBalance.value = cached
                    cached
                } else {
                    throw PaymentError.NetworkError("Failed to fetch wallet balance", e)
                }
            }
        }
    }

    suspend fun processWalletPayment(
        request: PaymentRequest,
        authToken: String,
        integrityToken: String?
    ): PaymentResult {
        return withContext(Dispatchers.IO) {
            val currentBalance = _walletBalance.value
                ?: throw PaymentError.NetworkError("Wallet balance not available")

            if (currentBalance.available < request.amount) {
                throw PaymentError.InsufficientFunds(
                    "Insufficient balance. Available: ${currentBalance.available} ${currentBalance.currency}"
                )
            }

            val payload = JSONObject().apply {
                put("transaction_id", request.transactionId)
                put("amount", request.amount.toPlainString())
                put("currency", request.currency)
                put("description", request.description)
                put("payment_method", request.paymentMethod.name)
                put("timestamp", request.timestamp)
                integrityToken?.let { put("integrity_token", it) }
                put("metadata", JSONObject(request.metadata))
            }

            val encryptedPayload = encryptionManager.encrypt(payload.toString())

            val requestBody = JSONObject().apply {
                put("encrypted_payload", encryptedPayload)
                put("device_id", getDeviceFingerprint())
            }

            val httpRequest = Request.Builder()
                .url("$BASE_URL/wallet/transaction")
                .addHeader("Authorization", "Bearer $authToken")
                .addHeader("X-Request-Id", request.transactionId)
                .addHeader("X-Idempotency-Key", request.transactionId)
                .addHeader("Content-Type", "application/json")
                .post(requestBody.toString().toRequestBody("application/json".toMediaType()))
                .build()

            val response = httpClient.newCall(httpRequest).execute()

            if (!response.isSuccessful) {
                val errorBody = response.body?.string()
                throw PaymentError.NetworkError(
                    "Transaction failed: ${response.code} - ${errorBody ?: "Unknown error"}"
                )
            }

            val responseBody = response.body?.string()
                ?: throw PaymentError.NetworkError("Empty response")

            val responseJson = JSONObject(responseBody)

            val result = PaymentResult(
                transactionId = request.transactionId,
                status = TransactionStatus.valueOf(responseJson.getString("status")),
                amount = request.amount,
                currency = request.currency,
                receiptToken = responseJson.optString("receipt_token", null),
                integrityVerified = responseJson.optBoolean("integrity_verified", false)
            )

            if (result.status == TransactionStatus.COMPLETED) {
                refreshBalance(authToken)
                recordTransaction(request, result)
            }

            result
        }
    }

    private fun cacheBalance(balance: WalletBalance) {
        val json = JSONObject().apply {
            put("available", balance.available.toPlainString())
            put("pending", balance.pending.toPlainString())
            put("currency", balance.currency)
            put("last_updated", balance.lastUpdated)
        }
        encryptionManager.secureStore(KEY_WALLET_BALANCE, json.toString())
    }

    private fun getCachedBalance(): WalletBalance? {
        return try {
            val cached = encryptionManager.secureRetrieve(KEY_WALLET_BALANCE) ?: return null
            val json = JSONObject(cached)
            WalletBalance(
                available = BigDecimal(json.getString("available")),
                pending = BigDecimal(json.getString("pending")),
                currency = json.getString("currency"),
                lastUpdated = json.getLong("last_updated")
            )
        } catch (e: Exception) {
            null
        }
    }

    private fun recordTransaction(request: PaymentRequest, result: PaymentResult) {
        val record = TransactionRecord(
            transactionId = request.transactionId,
            amount = request.amount,
            currency = request.currency,
            status = result.status,
            paymentMethod = request.paymentMethod,
            description = request.description,
            timestamp = System.currentTimeMillis(),
            receiptToken = result.receiptToken
        )
        _transactions.value = _transactions.value + record
    }

    private fun getDeviceFingerprint(): String {
        val fingerprint = "${Build.MANUFACTURER}|${Build.MODEL}|${Build.FINGERPRINT}"
        val md = MessageDigest.getInstance("SHA-256")
        val digest = md.digest(fingerprint.toByteArray())
        return Base64.encodeToString(digest, Base64.NO_WRAP)
    }
}

// ============================================================
// In-App Purchase Manager
// ============================================================

class InAppPurchaseManager(
    private val context: Context,
    private val encryptionManager: SecureEncryptionManager,
    private val httpClient: OkHttpClient
) {
    companion object {
        private const val TAG = "InAppPurchase"
        private const val BASE_URL = "https://api.yourpaymentserver.com/v1"
    }

    private var billingClient: BillingClient? = null
    private val _purchaseState = MutableStateFlow<PurchaseState>(PurchaseState.Idle)
    val purchaseState: StateFlow<PurchaseState> = _purchaseState.asStateFlow()

    private val pendingPurchases = ConcurrentHashMap<String, PaymentRequest>()

    sealed class PurchaseState {
        object Idle : PurchaseState()
        object Connecting : PurchaseState()
        object Connected : PurchaseState()
        data class ProductsLoaded(val products: List<ProductDetails>) : PurchaseState()
        data class PurchaseCompleted(val result: PaymentResult) : PurchaseState()
        data class PurchaseFailed(val error: PaymentError) : PurchaseState()
        object Disconnected : PurchaseState()
    }

    private val purchasesUpdatedListener = PurchasesUpdatedListener { billingResult, purchases ->
        CoroutineScope(Dispatchers.Main).launch {
            handlePurchaseUpdate(billingResult, purchases)
        }
    }

    fun initialize() {
        _purchaseState.value = PurchaseState.Connecting

        billingClient = BillingClient.newBuilder(context)
            .setListener(purchasesUpdatedListener)
            .enablePendingPurchases()
            .build()

        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    _purchaseState.value = PurchaseState.Connected
                    Log.d(TAG, "Billing client connected")
                } else {
                    _purchaseState.value = PurchaseState.PurchaseFailed(
                        PaymentError.BillingError(
                            "Billing setup failed: ${billingResult.debugMessage}",
                            billingResult.responseCode
                        )
                    )
                }
            }

            override fun onBillingServiceDisconnected() {
                _purchaseState.value = PurchaseState.Disconnected
                Log.w(TAG, "Billing service disconnected")
            }
        })
    }

    suspend fun queryProducts(productIds: List<String>, productType: String = BillingClient.ProductType.INAPP): List<ProductDetails> {
        val client = billingClient ?: throw PaymentError.BillingError("Billing client not initialized", -1)

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return suspendCancellableCoroutine { continuation ->
            client.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    _purchaseState.value = PurchaseState.ProductsLoaded(productDetailsList)
                    continuation.resume(productDetailsList)
                } else {
                    continuation.resumeWithException(
                        PaymentError.BillingError(
                            "Failed to query products: ${billingResult.debugMessage}",
                            billingResult.responseCode
                        )
                    )
                }
            }
        }
    }

    fun launchPurchaseFlow(
        activity: FragmentActivity,
        productDetails: ProductDetails,
        paymentRequest: PaymentRequest
    ) {
        val client = billingClient ?: throw PaymentError.BillingError("Billing client not initialized", -1)

        pendingPurchases[productDetails.productId] = paymentRequest

        val offerToken = productDetails.subscriptionOfferDetails?.firstOrNull()?.offerToken

        val productDetailsParamsBuilder = BillingFlowParams.ProductDetailsParams.newBuilder()
            .setProductDetails(productDetails)

        offerToken?.let { productDetailsParamsBuilder.setOfferToken(it) }

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(listOf(productDetailsParamsBuilder.build()))
            .build()

        val result = client.launchBillingFlow(activity, billingFlowParams)
        if (result.responseCode != BillingClient.BillingResponseCode.OK) {
            _purchaseState.value = PurchaseState.PurchaseFailed(
                PaymentError.BillingError(
                    "Failed to launch purchase flow: ${result.debugMessage}",
                    result.responseCode
                )
            )
        }
    }

    private suspend fun handlePurchaseUpdate(billingResult: BillingResult, purchases: List<Purchase>?) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
            for (purchase in purchases) {
                handlePurchase(purchase)
            }
        } else if (billingResult.responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
            _purchaseState.value = PurchaseState.PurchaseFailed(
                PaymentError.BillingError("Purchase cancelled by user", billingResult.responseCode)
            )
        } else {
            _purchaseState.value = PurchaseState.PurchaseFailed(
                PaymentError.BillingError(
                    "Purchase failed: ${billingResult.debugMessage}",
                    billingResult.responseCode
                )
            )
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            // Verify purchase on server
            val verified = verifyPurchaseOnServer(purchase)

            if (verified) {
                // Acknowledge the purchase
                if (!purchase.isAcknowledged) {
                    acknowledgePurchase(purchase)
                }

                val productId = purchase.products.firstOrNull() ?: ""
                val paymentRequest = pendingPurchases.remove(productId)

                _purchaseState.value = PurchaseState.PurchaseCompleted(
                    PaymentResult(
                        transactionId = paymentRequest?.transactionId ?: purchase.orderId ?: UUID.randomUUID().toString(),
                        status = TransactionStatus.COMPLETED,
                        amount = paymentRequest?.amount ?: BigDecimal.ZERO,
                        currency = paymentRequest?.currency ?: "USD",
                        receiptToken = purchase.purchaseToken,
                        integrityVerified = true
                    )
                )
            } else {
                _purchaseState.value = PurchaseState.PurchaseFailed(
                    PaymentError.ServerVerificationFailed("Purchase verification failed on server")
                )
            }
        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            _purchaseState.value = PurchaseState.PurchaseCompleted(
                PaymentResult(
                    transactionId = purchase.orderId ?: UUID.randomUUID().toString(),
                    status = TransactionStatus.PENDING,
                    amount = BigDecimal.ZERO,
                    currency = "USD",
                    receiptToken = purchase.purchaseToken
                )
            )
        }
    }

    private suspend fun verifyPurchaseOnServer(purchase: Purchase): Boolean {
        return withContext(Dispatchers.IO) {
            try {
                val payload = JSONObject().apply {
                    put("purchase_token", purchase.purchaseToken)
                    put("product_id", purchase.products.firstOrNull())
                    put("order_id", purchase.orderId)
                    put("package_name", context.packageName)
                    put("purchase_time", purchase.purchaseTime)
                    put("purchase_state", purchase.purchaseState)
                    put("signature", purchase.signature)
                    put("original_json", purchase.originalJson)
                }

                val request = Request.Builder()
                    .url("$BASE_URL/purchases/verify")
                    .addHeader("Content-Type", "application/json")
                    .addHeader("X-Request-Id", UUID.randomUUID().toString())
                    .post(payload.toString().toRequestBody("application/json".toMediaType()))
                    .build()

                val response = httpClient.newCall(request).execute()
                if (response.isSuccessful) {
                    val body = response.body?.string()
                    val json = JSONObject(body ?: "{}")
                    json.optBoolean("verified", false)
                } else {
                    false
                }
            } catch (e: Exception) {
                Log.e(TAG, "Server verification failed", e)
                false
            }
        }
    }

    private suspend fun acknowledgePurchase(purchase: Purchase) {
        val client = billingClient ?: return

        val params = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        suspendCancellableCoroutine<Unit> { continuation ->
            client.acknowledgePurchase(params) { billingResult ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d(TAG, "Purchase acknowledged successfully")
                } else {
                    Log.e(TAG, "Failed to acknowledge purchase: ${billingResult.debugMessage}")
                }
                continuation.resume(Unit)
            }
        }
    }

    suspend fun consumePurchase(purchaseToken: String): Boolean {
        val client = billingClient ?: return false

        val params = ConsumeParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()

        return suspendCancellableCoroutine { continuation ->
            client.consumeAsync(params) { billingResult, _ ->
                continuation.resume(billingResult.responseCode == BillingClient.BillingResponseCode.OK)
            }
        }
    }

    fun disconnect() {
        billingClient?.endConnection()
        billingClient = null
        _purchaseState.value = PurchaseState.Disconnected
    }
}

// ============================================================
// Audit Logger
// ============================================================

class SecurityAuditLogger(private val encryptionManager: SecureEncryptionManager) {

    companion object {
        private const val KEY_AUDIT_LOG = "security_audit_log"
        private const val MAX_LOG_ENTRIES = 500
    }

    fun logEvent(
        eventType: String,
        transactionId: String? = null,
        details: Map<String, String> = emptyMap(),
        severity: String = "INFO"
    ) {
        try {
            val entry = JSONObject().apply {
                put("timestamp", System.currentTimeMillis())
                put("event_type", eventType)
                put("severity", severity)
                transactionId?.let { put("transaction_id", it) }
                put("details", JSONObject(details))
            }

            val existingLog = encryptionManager.secureRetrieve(KEY_AUDIT_LOG) ?: "[]"
            val logArray = org.json.JSONArray(existingLog)

            logArray.put(entry)

            // Trim old entries
            while (logArray.length() > MAX_LOG_ENTRIES) {
                logArray.remove(0)
            }

            encryptionManager.secureStore(KEY_AUDIT_LOG, logArray.toString())
        } catch (e: Exception) {
            Log.e("AuditLogger", "Failed to log security event", e)
        }
    }

    fun getAuditLog(): String {
        return encryptionManager.secureRetrieve(KEY_AUDIT_LOG) ?: "[]"
    }

    fun clearAuditLog() {
        encryptionManager.secureStore(KEY_AUDIT_LOG, "[]")
    }
}

// ============================================================
// Main Payment Processor
// ============================================================

class PaymentProcessor private constructor(
    private val context: Context,
    private val activity: FragmentActivity?,
    private val encryptionManager: SecureEncryptionManager,
    private val integrityChecker: DeviceIntegrityChecker,
    private val rateLimiter: TransactionRateLimiter,
    private val biometricAuthManager: BiometricAuthManager?,
    private val walletManager: WalletManager,
    private val inAppPurchaseManager: InAppPurchaseManager,
    private val auditLogger: SecurityAuditLogger
) {
    companion object {
        private const val TAG = "PaymentProcessor"
    }

    private val _paymentEvents = MutableSharedFlow<PaymentResult>(replay = 0)
    val paymentEvents: SharedFlow<PaymentResult> = _paymentEvents.asSharedFlow()

    private val isProcessing = AtomicBoolean(false)

    class Builder(private val context: Context) {
        private var activity: FragmentActivity? = null
        private var httpClient: OkHttpClient? = null

        fun setActivity(activity: FragmentActivity) = apply { this.activity = activity }
        fun setHttpClient(client: OkHttpClient) = apply { this.httpClient = client }

        fun build(): PaymentProcessor {
            val client = httpClient ?: OkHttpClient.Builder()
                .connectTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
                .readTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
                .writeTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
                .certificatePinner(
                    CertificatePinner.Builder()
                        // TODO: Add your server's certificate pins
                        // .add("api.yourpaymentserver.com", "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=")
                        .build()
                )
                .addInterceptor { chain ->
                    val original = chain.request()
                    val request = original.newBuilder()
                        .addHeader("X-Platform", "Android")
                        .addHeader("X-App-Version", getAppVersion())
                        .addHeader("X-Device-Model", "${Build.MANUFACTURER} ${Build.MODEL}")
                        .addHeader("X-OS-Version", "Android ${Build.VERSION.RELEASE}")
                        .build()
                    chain.proceed(request)
                }
                .build()

            val encryptionManager = SecureEncryptionManager(context)
            val integrityChecker = DeviceIntegrityChecker(context)
            val rateLimiter = TransactionRateLimiter()
            val biometricAuthManager = activity?.let { BiometricAuthManager(it) }
            val walletManager = WalletManager(context, encryptionManager, client)
            val inAppPurchaseManager = InAppPurchaseManager(context, encryptionManager, client)
            val auditLogger = SecurityAuditLogger(encryptionManager)

            return PaymentProcessor(
                context = context,
                activity = activity,
                encryptionManager = encryptionManager,
                integrityChecker = integrityChecker,
                rateLimiter = rateLimiter,
                biometricAuthManager = biometricAuthManager,
                walletManager = walletManager,
                inAppPurchaseManager = inAppPurchaseManager,
                auditLogger = auditLogger
            )
        }

        private fun getAppVersion(): String {
            return try {
                val pInfo = context.packageManager.getPackageInfo(context.packageName, 0)
                pInfo.versionName ?: "unknown"
            } catch (e: Exception) {
                "unknown"
            }
        }
    }

    fun initialize() {
        inAppPurchaseManager.initialize()
        auditLogger.logEvent("PAYMENT_PROCESSOR_INITIALIZED")
    }

    suspend fun processPayment(
        request: PaymentRequest,
        authToken: String,
        requireBiometric: Boolean = true
    ): PaymentResult {
        if (!isProcessing.compareAndSet(false, true)) {
            throw PaymentError.SecurityViolation("Another payment is already being processed")
        }

        try {
            auditLogger.logEvent(
                "PAYMENT_INITIATED",
                request.transactionId,
                mapOf(
                    "amount" to request.amount.toPlainString(),
                    "currency" to request.currency,
                    "method" to request.paymentMethod.name
                )
            )

            // Step 1: Rate limiting
            rateLimiter.checkRateLimit()

            // Step 2: Device integrity check
            val integrityResult = integrityChecker.performFullIntegrityCheck()
            auditLogger.logEvent(
                "INTEGRITY_CHECK",
                request.transactionId,
                mapOf(
                    "risk_score" to integrityResult.riskScore.toString(),
                    "is_valid" to integrityResult.isIntegrityValid.toString(),
                    "is_emulator" to integrityResult.isEmulator.toString(),
                    "is_rooted" to integrityResult.isRooted.toString()
                )
            )

            if (!integrityResult.isIntegrityValid) {
                auditLogger.logEvent(
                    "INTEGRITY_CHECK_FAILED",
                    request.transactionId,
                    integrityResult.checks.mapValues { it.value.toString() },
                    severity = "CRITICAL"
                )
                throw PaymentError.IntegrityCheckFailed(
                    "Device integrity check failed. Risk score: ${integrityResult.riskScore}"
                )
            }

            // Step 3: Biometric authentication (for elevated/critical security)
            if (requireBiometric && request.securityLevel != SecurityLevel.STANDARD) {
                val biometricAuth = biometricAuthManager
                    ?: throw PaymentError.BiometricAuthFailed("Biometric authentication not available")

                if (biometricAuth.isBiometricAvailable()) {
                    val authenticated = biometricAuth.authenticate(
                        title = "Confirm Payment",
                        subtitle = "Verify your identity to pay ${request.amount} ${request.currency}"
                    )
                    if (!authenticated) {
                        auditLogger.logEvent(
                            "BIOMETRIC_AUTH_CANCELLED",
                            request.transactionId,
                            severity = "WARN"
                        )
                        throw PaymentError.BiometricAuthFailed("Biometric authentication cancelled")
                    }
                    auditLogger.logEvent("BIOMETRIC_AUTH_SUCCESS", request.transactionId)
                }
            }

            // Step 4: Process based on payment method
            val result = when (request.paymentMethod) {
                PaymentMethod.WALLET_BALANCE, PaymentMethod.WALLET_TOP_UP -> {
                    walletManager.processWalletPayment(
                        request,
                        authToken,
                        integrityResult.integrityToken
                    )
                }

                PaymentMethod.IN_APP_PURCHASE -> {
                    // For IAP, the flow is initiated via launchPurchaseFlow
                    // This returns a pending result
                    PaymentResult(
                        transactionId = request.transactionId,
                        status = TransactionStatus.REQUIRES_VERIFICATION,
                        amount = request.amount,
                        currency = request.currency,
                        integrityVerified = integrityResult.isIntegrityValid
                    )
                }
            }

            // Step 5: Record and emit result
            rateLimiter.recordTransaction()
            auditLogger.logEvent(
                "PAYMENT_COMPLETED",
                request.transactionId,
                mapOf(
                    "status" to result.status.name,
                    "integrity_verified" to result.integrityVerified.toString()
                )
            )

            _paymentEvents.emit(result)
            return result

        } catch (e: PaymentError) {
            rateLimiter.recordFailure()
            auditLogger.logEvent(
                "PAYMENT_FAILED",
                request.transactionId,
                mapOf("error" to (e.message ?: "Unknown error")),
                severity = "ERROR"
            )

            val failedResult = PaymentResult(
                transactionId = request.transactionId,
                status = TransactionStatus.FAILED,
                amount = request.amount,
                currency = request.currency,
                errorMessage = e.message
            )
            _paymentEvents.emit(failedResult)
            throw e
        } catch (e: Exception) {
            rateLimiter.recordFailure()
            auditLogger.logEvent(
                "PAYMENT_ERROR",
                request.transactionId,
                mapOf("error" to (e.message ?: "Unknown error")),
                severity = "ERROR"
            )
            throw PaymentError.NetworkError("Unexpected error during payment", e)
        } finally {
            isProcessing.set(false)
        }
    }

    suspend fun launchInAppPurchase(
        productDetails: ProductDetails,
        paymentRequest: PaymentRequest
    ) {
        val act = activity ?: throw PaymentError.BillingError("Activity not set", -1)
        inAppPurchaseManager.launchPurchaseFlow(act, productDetails, paymentRequest)
    }

    suspend fun queryProducts(
        productIds: List<String>,
        productType: String = BillingClient.ProductType.INAPP
    ): List<ProductDetails> {
        return inAppPurchaseManager.queryProducts(productIds, productType)
    }

    suspend fun getWalletBalance(authToken: String): WalletBalance {
        return walletManager.refreshBalance(authToken)
    }

    fun observeWalletBalance(): StateFlow<WalletBalance?> = walletManager.walletBalance

    fun observePurchaseState(): StateFlow<InAppPurchaseManager.PurchaseState> =
        inAppPurchaseManager.purchaseState

    fun observeTransactions(): StateFlow<List<TransactionRecord>> = walletManager.transactions

    suspend fun performSecurityCheck(): DeviceIntegrityResult {
        return integrityChecker.performFullIntegrityCheck()
    }

    fun getAuditLog(): String = auditLogger.getAuditLog()

    fun destroy() {
        inAppPurchaseManager.disconnect()
        auditLogger.logEvent("PAYMENT_PROCESSOR_DESTROYED")
    }
}

